import{c as a,Q as t,j as o,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"@muhaven/mcp — overview","description":"Bring your own LLM. Drive MuHaven from Claude Code, Claude Desktop, or Cursor.","frontmatter":{"title":"@muhaven/mcp — overview","description":"Bring your own LLM. Drive MuHaven from Claude Code, Claude Desktop, or Cursor."},"headers":[],"relativePath":"mcp/overview.md","filePath":"mcp/overview.md","lastUpdated":1778951051000}'),s={name:"mcp/overview.md"};function r(i,e,p,l,d,c){return t(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="muhaven-mcp" tabindex="-1"><code>@muhaven/mcp</code> <a class="header-anchor" href="#muhaven-mcp" aria-label="Permalink to &quot;\`@muhaven/mcp\`&quot;">​</a></h1><p><code>@muhaven/mcp</code> is a <a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol</a> server that turns any MCP-aware LLM host (Claude Code, Claude Desktop, Cursor, future MCP hosts) into a front-end for your MuHaven RWA portfolio.</p><p>You install it once, complete a one-time passkey-bound device authorization, and from then on you can ask <strong>the LLM you already trust</strong> to read your encrypted-balance portfolio, propose trades, manage policy, and — if you&#39;re an issuer — drive distributions and KYC. All without ever pasting an API key, an RPC URL, or a private key into an LLM context.</p><h2 id="what-you-get" tabindex="-1">What you get <a class="header-anchor" href="#what-you-get" aria-label="Permalink to &quot;What you get&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Package</strong></td><td><code>@muhaven/mcp</code> on npm (published with OIDC + Sigstore provenance)</td></tr><tr><td><strong>Format</strong></td><td>MCPB (Model Context Protocol Bundle) — official MCP package format</td></tr><tr><td><strong>Binaries</strong></td><td><code>muhaven-mcp</code> (STDIO subprocess) + <code>muhaven-broker</code> (long-lived per-user daemon)</td></tr><tr><td><strong>Tools</strong></td><td>22 across 5 groups: read · position · policy · issuer · governance</td></tr><tr><td><strong>Auth</strong></td><td>OAuth 2.0 Device Authorization Grant (RFC 8628) → scoped JWT in OS keychain</td></tr><tr><td><strong>Hosts</strong></td><td>Claude Code (verified end-to-end), Claude Desktop and Cursor (same <code>.mcp.json</code> shape)</td></tr></tbody></table><h2 id="architecture-in-one-diagram" tabindex="-1">Architecture in one diagram <a class="header-anchor" href="#architecture-in-one-diagram" aria-label="Permalink to &quot;Architecture in one diagram&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─── Your machine ──────────────────────────────────────────┐</span></span>
<span class="line"><span>│                                                            │</span></span>
<span class="line"><span>│  Claude Code / Claude Desktop / Cursor                     │</span></span>
<span class="line"><span>│   │ STDIO (JSON-RPC)                                       │</span></span>
<span class="line"><span>│   ▼                                                        │</span></span>
<span class="line"><span>│  muhaven-mcp ─── named pipe / Unix socket ──► muhaven-     │</span></span>
<span class="line"><span>│   │              (broker holds JWT + sig key)   broker     │</span></span>
<span class="line"><span>│   │                                                        │</span></span>
<span class="line"><span>│   │ HTTPS to the MuHaven backend                           │</span></span>
<span class="line"><span>└───┼────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>    ▼</span></span>
<span class="line"><span>  https://api.muhaven.app/api/v1/...</span></span></code></pre></div><p>Two processes on <strong>your</strong> machine:</p><ol><li><strong><code>muhaven-mcp</code></strong> — a STDIO subprocess the host LLM spawns on demand. Speaks JSON-RPC to the host, HTTPS to the MuHaven backend. <strong>Never</strong> sees your signing key.</li><li><strong><code>muhaven-broker</code></strong> — a long-lived per-user daemon. Holds the JWT and the ZeroDev session-key private half in your OS keychain. Listens on a Unix socket (POSIX) or named pipe (Windows). <strong>Never</strong> speaks TCP.</li></ol><p>The split is the load-bearing security control: an attacker who jailbreaks the LLM cannot exfiltrate your signing key without also compromising a separate process running under your user.</p><h2 id="when-to-use-mcp-vs-the-other-surfaces" tabindex="-1">When to use MCP vs the other surfaces <a class="header-anchor" href="#when-to-use-mcp-vs-the-other-surfaces" aria-label="Permalink to &quot;When to use MCP vs the other surfaces&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>If yes → MCP</th></tr></thead><tbody><tr><td>Do you already chat with Claude / a host LLM every day?</td><td>✅</td></tr><tr><td>Do you want to sit MuHaven next to Notion / GitHub / Gmail MCPs in one chat?</td><td>✅</td></tr><tr><td>Do you have a budget for your own LLM tokens?</td><td>✅</td></tr><tr><td>Do you want a guided wizard with click-through previews?</td><td>❌ Use <a href="/havenbot/overview">HavenBot</a></td></tr><tr><td>Do you want phone-first one-tap actions?</td><td>❌ Use <a href="/openclaw/telegram-bot">Telegram</a></td></tr></tbody></table><p>Five reasons to pick MCP over HavenBot:</p><ol><li><strong>Use the LLM you already trust.</strong> Not locked to MuHaven&#39;s server-managed LLM. Connect Claude Sonnet 4.6, Claude Opus 4.7, or any future model your host supports — bring your own provider key.</li><li><strong>Multi-agent workflows.</strong> Sit MuHaven alongside your other MCP servers. &quot;Pull my MuHaven portfolio + cross-reference with my Notion investment thesis + email a summary to my CPA via Gmail&quot; becomes one chat turn.</li><li><strong>Privacy by construction.</strong> The MCP server NEVER decrypts FHE handles. The LLM NEVER sees your private key (broker holds it). Your host&#39;s LLM context never sees your JWT (the broker holds that too).</li><li><strong>Programmatic automation.</strong> Once installed, the same surface is available to scheduled cron-style automations: &quot;every Friday at 17:00, check yields and propose a claim if any are &gt;$10.&quot;</li><li><strong>Open standards.</strong> Built on MCP (Anthropic / open spec), OAuth 2.0 Device Authorization Grant (RFC 8628), ZeroDev passkey-bound smart account (EIP-4337), Sigstore signing. Nothing proprietary.</li></ol><h2 id="what-mcp-looks-like-in-claude-code" tabindex="-1">What MCP looks like in Claude Code <a class="header-anchor" href="#what-mcp-looks-like-in-claude-code" aria-label="Permalink to &quot;What MCP looks like in Claude Code&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ claude</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&gt; What does my muhaven portfolio look like?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[muhaven] muhaven.read.portfolio()</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>  &quot;positions&quot;: [],</span></span>
<span class="line"><span>  &quot;total_tokens&quot;: 0</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Your MuHaven portfolio is empty — you don&#39;t hold any RWA tokens yet.</span></span>
<span class="line"><span>Want me to draft a buy proposal? I can call muhaven.position.buy with</span></span>
<span class="line"><span>an amount and token of your choice.</span></span></code></pre></div><p>The LLM sees only the <strong>aggregate</strong> the backend chose to return. No encrypted handle, no cleartext balance. If you ask &quot;buy 100 mhUSDC of <code>&lt;TOKEN&gt;</code>&quot;, the LLM produces a tool_call → the broker signs → the result is an unsigned UserOp envelope. The LLM never auto-submits.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><div class="mh-card-grid"><a class="mh-card" href="/mcp/install"><h3>Install</h3><p>Get @muhaven/mcp running in Claude Code, Desktop, or Cursor.</p></a><a class="mh-card" href="/mcp/first-chat"><h3>First chat</h3><p>Walk through your first portfolio query end-to-end.</p></a><a class="mh-card" href="/mcp/playbook"><h3>Playbook — scenarios</h3><p>Multi-MCP workflows, scheduled checks, cross-tool prompts that just work.</p></a><a class="mh-card" href="/mcp/tools"><h3>Tool catalog</h3><p>The 22 tools across read / position / policy / issuer / governance.</p></a><a class="mh-card" href="/mcp/broker"><h3>Broker daemon</h3><p>How the broker handles your keys, sockets, and OS keychain.</p></a></div>`,19)])])}const m=a(s,[["render",r]]);export{u as __pageData,m as default};
